class Solution {
public:
    int minimumScore(string s, string t) {
        int n = s.size(), m = t.size();
        int i = 0, j = 0, left = 0, right = 0, ans = m;
        while (i < n && j < m) {
            if (s[i] == t[j]) j++;
            if (j == m) return 0;
            if (s[i] != t[j]) {
                left = i;
                while (j < m && s[i] != t[j]) {
                    right = i;
                    i++;
                    j++;
                }
                if (j == m) return right - left + 1;
                ans = min(ans, right - left + 1);
            }
            i++;
        }
        return ans;
    }
};
```

